1	/**
2	 * Structured logger that writes to stderr (stdout is reserved for MCP protocol).
3	 */
4	
5	import { LOG_LEVEL_VALUES, type LogLevel, type LogMeta } from "./types.js";
6	import { getConfig } from "./config.js";
7	
8	function formatMeta(meta?: LogMeta): string {
9	  if (!meta) return "";
10	  try {
11	    return ` ${JSON.stringify(meta)}`;
12	  } catch {
13	    return " [meta unavailable]";
14	  }
15	}
16	
17	/**
18	 * Write a structured log line to stderr.
19	 * Only emits if `level` meets the configured threshold.
20	 */
21	export function log(level: LogLevel, message: string, meta?: LogMeta): void {
22	  const levelValue = LOG_LEVEL_VALUES[level];
23	  const config = getConfig();
24	  if (levelValue > config.logLevelValue) return;
25	
26	  const timestamp = new Date().toISOString();
27	  const line = `[${timestamp}] [${level}] ${message}${formatMeta(meta)}\n`;
28	  process.stderr.write(line);
29	}
30	
31	/** Convenience: log an error with optional stack trace. */
32	export function logError(context: string, error: unknown): void {
