1	/**
2	 * Barrel module — registers all MCP tools on the server.
3	 */
4	
5	import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
6	import { registerVaultList } from "./vault-list.js";
7	import { registerItemLookup } from "./item-lookup.js";
8	import { registerItemDelete } from "./item-delete.js";
9	import { registerPasswordCreate } from "./password-create.js";
10	import { registerPasswordRead } from "./password-read.js";
11	import { registerPasswordUpdate } from "./password-update.js";
12	import { registerPasswordGenerate } from "./password-generate.js";
13	import { registerPasswordGenerateMemorable } from "./password-generate-memorable.js";
14	
15	/** Register every tool with the MCP server. */
16	export function registerAllTools(server: McpServer): void {
17	  registerVaultList(server);
18	  registerItemLookup(server);
19	  registerItemDelete(server);
20	  registerPasswordCreate(server);
21	  registerPasswordRead(server);
22	  registerPasswordUpdate(server);
23	  registerPasswordGenerate(server);
24	  registerPasswordGenerateMemorable(server);
25	}

1	/**
2	 * Tests for MCP tool handlers with mocked 1Password client.
3	 */
4	
5	import { describe, it, expect, vi, beforeEach } from "vitest";
6	
7	// Mock the client module before importing tools
8	vi.mock("../src/client.js", () => ({
9	  getClient: vi.fn(),
10	  requireServiceAccountToken: vi.fn(() => "mock-token"),
11	  resetClient: vi.fn(),
12	}));
13	
14	// Mock the logger to suppress output during tests
15	vi.mock("../src/logger.js", () => ({
16	  log: vi.fn(),
17	  logError: vi.fn(),
18	}));
19	
20	import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
21	import { getClient } from "../src/client.js";
22	import { registerAllTools } from "../src/tools/index.js";
23	
24	const mockedGetClient = vi.mocked(getClient);
25	
26	describe("MCP Tools", () => {
27	  let server: McpServer;
28	  let registeredTools: Map<string, any>;
29	
30	  beforeEach(() => {
31	    vi.clearAllMocks();
32	    server = new McpServer({ name: "test", version: "0.0.0" });
33	
34	    // Spy on server.tool to capture registered handlers
35	    registeredTools = new Map();
36	    const originalTool = server.tool.bind(server);
37	    vi.spyOn(server, "tool").mockImplementation((...args: any[]) => {
38	      // The 4-arg overload: (name, description, schema, handler)
39	      if (args.length === 4) {
40	        registeredTools.set(args[0], {
41	          description: args[1],
42	          schema: args[2],
43	          handler: args[3],
44	        });
45	      }
46	      return originalTool(...args);
47	    });
48	
49	    registerAllTools(server);
50	  });
51	
52	  it("registers all 8 tools", () => {
53	    expect(registeredTools.size).toBe(8);
54	    expect(registeredTools.has("vault_list")).toBe(true);
55	    expect(registeredTools.has("item_lookup")).toBe(true);
56	    expect(registeredTools.has("item_delete")).toBe(true);
57	    expect(registeredTools.has("password_create")).toBe(true);
58	    expect(registeredTools.has("password_read")).toBe(true);
59	    expect(registeredTools.has("password_update")).toBe(true);
60	    expect(registeredTools.has("password_generate")).toBe(true);
61	    expect(registeredTools.has("password_generate_memorable")).toBe(true);
62	  });
63	
64	  it("all tools have descriptions", () => {
65	    for (const [name, tool] of registeredTools) {
66	      expect(tool.description, `${name} should have a description`).toBeTruthy();
67	      expect(typeof tool.description).toBe("string");
68	      expect(tool.description.length).toBeGreaterThan(10);
69	    }
70	  });
71	
72	  describe("vault_list", () => {
73	    it("returns vault summaries", async () => {
74	      mockedGetClient.mockResolvedValue({
75	        vaults: {
76	          list: vi.fn().mockResolvedValue([
77	            { id: "v1", name: "Personal", description: "My vault", type: "USER_CREATED" },
78	            { id: "v2", name: "Shared", description: null, type: "USER_CREATED" },
79	          ]),
80	        },
